    //     {
    //         "entryPrice": "6563.66500",
    //         "marginType": "isolated",
    //         "isAutoAddMargin": "false",
    //         "isolatedMargin": "15517.54150468",
    //         "leverage": "10",
    //         "liquidationPrice": "5930.78",
    //         "markPrice": "6679.50671178",
    //         "maxNotionalValue": "20000000",
    //         "positionSide": "LONG",
    //         "positionAmt": "20.000",
    //         "symbol": "BTCUSDT",
    //         "unRealizedProfit": "2316.83423560",
    //         "updateTime": 1625474304765
    //     }
